// EnemyAIController.h — the brain
UCLASS()
class AEnemyAIController : public AAIController
{
    GENERATED_BODY()
public:
    AEnemyAIController();

    UPROPERTY(EditDefaultsOnly, Category = "AI")
    UBehaviorTree* BehaviorTreeAsset;

    UPROPERTY(VisibleAnywhere, BlueprintReadOnly)
    UAIPerceptionComponent* AIPerception;

protected:
    virtual void OnPossess(APawn* InPawn) override;

    UFUNCTION()
    void OnPerceptionUpdated(const TArray<AActor*>& UpdatedActors);
};

// EnemyAIController.cpp
AEnemyAIController::AEnemyAIController()
{
    AIPerception = CreateDefaultSubobject<UAIPerceptionComponent>(TEXT("AIPerception"));

    // Configure sight
    UAISenseConfig_Sight* SightConfig = CreateDefaultSubobject<UAISenseConfig_Sight>(TEXT("SightConfig"));
    SightConfig->SightRadius = 1500.f;
    SightConfig->LoseSightRadius = 2000.f;
    SightConfig->PeripheralVisionAngleDegrees = 60.f;
    AIPerception->ConfigureSense(*SightConfig);
    AIPerception->SetDominantSense(UAISenseConfig_Sight::StaticClass());
}

void AEnemyAIController::OnPossess(APawn* InPawn)
{
    Super::OnPossess(InPawn);
    AIPerception->OnPerceptionUpdated.AddDynamic(this, &AEnemyAIController::OnPerceptionUpdated);
    if (BehaviorTreeAsset)
    {
        RunBehaviorTree(BehaviorTreeAsset);
    }
}

void AEnemyAIController::OnPerceptionUpdated(const TArray<AActor*>& UpdatedActors)
{
    // Update Blackboard with what we see
    AActor* BestTarget = nullptr;
    for (AActor* Actor : UpdatedActors)
    {
        FActorPerceptionBlueprintInfo Info;
        AIPerception->GetActorsPerception(Actor, Info);
        for (const auto& Stimulus : Info.LastSensedStimuli)
        {
            if (Stimulus.WasSuccessfullySensed())
            {
                BestTarget = Actor;
                break;
            }
        }
    }
    GetBlackboardComponent()->SetValueAsObject("TargetActor", BestTarget);
}

// EnemyCharacter.h — the body (thin class)
UCLASS()
class AEnemyCharacter : public ACharacter
{
    GENERATED_BODY()
public:
    AEnemyCharacter();
    // Health, mesh, animations — no AI logic here
};

AEnemyCharacter::AEnemyCharacter()
{
    AIControllerClass = AEnemyAIController::StaticClass();
    AutoPossessAI = EAutoPossessAI::PlacedInWorldOrSpawned;
}
